import './index.css';

import {
  useEffect,
  useState
} from 'react';

import {
  createSubject,
  getSubjects
} from '../../services/subjectService';

function SubjectManagementPage() {

  const [subjects, setSubjects] =
    useState([]);

  const [formData, setFormData] =
    useState({
      subject_name: '',
      semester: ''
    });

  const loadSubjects =
    async () => {

    const data =
      await getSubjects();

    setSubjects(data);

  };

  useEffect(() => {

    loadSubjects();

  }, []);

  const handleChange =
    (e) => {

    setFormData({
      ...formData,
      [e.target.name]:
      e.target.value
    });

  };

  const handleSubmit =
    async (e) => {

    e.preventDefault();

    await createSubject(formData);

    alert('Subject Created');

    loadSubjects();

  };

  return (

    <div className="subject-page">

      <h1>
        Subject Management
      </h1>

      <form onSubmit={handleSubmit}>

        <input
          type="text"
          name="subject_name"
          placeholder="Subject Name"
          onChange={handleChange}
        />

        <input
          type="number"
          name="semester"
          placeholder="Semester"
          onChange={handleChange}
        />

        <button type="submit">
          Create Subject
        </button>

      </form>

      <div className="subject-list">

        {subjects.map((subject) => (

          <div
            key={subject.id}
            className="subject-card"
          >

            <h3>
              {subject.subject_name}
            </h3>

            <p>
              Semester:
              {subject.semester}
            </p>

          </div>

        ))}

      </div>

    </div>

  );

}

export default SubjectManagementPage;
